for (const item of $input.all()) {

  // 1. Get the data
  // Note: Based on your screenshot, the data is inside a "query" object.
  const inputData = item.json.query; 

  // 2. Parse Scores 
  // We use parseInt() because webhook query parameters often come in as strings (e.g., "5")
  // We use ( || 0 ) as a fallback in case a score is missing.
  const scoreP = parseInt(inputData.scores_p || 0);
  const scoreA = parseInt(inputData.scores_a || 0);
  const scoreV = parseInt(inputData.scores_v || 0);
  const scoreE = parseInt(inputData.scores_e || 0);

  // 3. Calculate Total Score (Flowchart Step B)
  const totalScore = scoreP + scoreA + scoreV + scoreE;

  // 4. Determine Status Logic (Flowchart Steps C, D, E)
  let status = 'PAVE Scored'; // Default status (No branch)

  if (totalScore >= 18) {
    status = 'Approved for Briefing'; // (Yes branch)
  }

  // 5. Append these new values to the item
  // This makes them available for the SharePoint nodes later
  item.json.total_score = totalScore;
  item.json.pave_status = status;
}

// Return the items with the new fields added
return $input.all();

