// 1. Get the target brand name from the 'GetBrandDetails1' node
// We use logical OR (||) to fallback to "VitCornu" if the expression is empty for testing
const targetBrand = $('GetBrandDetails').first().json.query.brand_name;

// 2. Find the FIRST item where the Title matches the targetBrand
// .find() stops immediately after finding the first match, effectively handling the "duplicate" requirement
const matchedItem = items.find(item => item.json.fields.Title === targetBrand);

// 3. If no match is found, return an empty array (stops execution safely)
if (!matchedItem) {
  return [];
}

// 4. Format the found item
const fields = matchedItem.json.fields;

return [
  {
    json: {
      row_number: fields.ID, // Optional as requested
      Brand_ID: fields.ID,
      Brand: fields.Title,
      Target_Persona: fields.Target_Persona,
      Tone_of_Voice: fields.Tone_of_Voice,
      Product_Context: fields.Product_Context,

      // Handle potentially missing text field
      Compliance_Disclaimer_Block: fields.Compliance_Disclaimer_Block || "",

      // Extract URL from the nested object safely
      CSS_Wrapper_Link: fields.CSS_Wrapper_Link ? fields.CSS_Wrapper_Link.Url : ""
    }
  }
];

// 1. Get the status value from the 'FetchItembyStatus' node
const targetStatus = $('FetchItembyStatus').first().json.query?.status;

// 2. Filter the items based on the Status field
const filteredItems = items.filter(item => {
  return item.json.fields && item.json.fields.Status === targetStatus;
});

// 3. IF NO MATCHES FOUND: Return the keys with empty/default values
if (filteredItems.length === 0) {
  return[
    {
      json: {
        row_number: "",
        ID: "",
        Title: "",
        Target_Brand: "",
        Status: targetStatus || "", // Keeps the status you searched for, or empty
        Approved_Outline: "",
